var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"아이고야……. 한참 재밌어질 때였는데 더 못 움직이겠네.","JPN":"いたたたた……だいぶ盛り上がってきたのに、これ以上動けそうにないわ。","ENG":"Ow… This was just starting to get really fun, but I can't move a muscle now.","TWN":"哎唷喂呀……人家打得正開心呢，現在都不能動了啦！"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"사지에 단순 골절 감지. 깁스를 한 상태에서도 지금처럼 날뛸 수 있을지 궁금하군요.","JPN":"手足に複数の単純骨折を感知。ギプスをした状態でも今のように暴れられるか気になりますね。","ENG":"Fractures detected in all limbs. I wonder if you'll still thrash about so wildly in a full body cast.","TWN":"感應到四肢骨，我很好奇在包著石膏的狀態下，你還能這麼活潑嗎？"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"하나는 남겨 주지. 이대로 돌아가면 난 잔혹한 고용주한테 속수무책으로 당할 거야. 흑흑.","JPN":"1か所くらいは残しといてよ。このまま戻ったら血も涙もないクライアントにボコボコにされちゃうもん、ぐすん。","ENG":"You could've left at least one limb intact. If I go back like this, I'll be helpless in front of my big jerk employer. *Sob*","TWN":"我跟你說，我這樣回去，就只能任殘忍的主人宰割，呵呵。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그 상태로 잘도 떠드는군요. 통각 신경도 정상적으로 작동하는 휴먼이.","JPN":"そんな状態でもおしゃべりですね。痛覚神経も正常に作動するヒューマンのはずですが。","ENG":"Yet you seem to have no trouble running your mouth. Especially for a human whose sense of pain remains fully functional.","TWN":"人類，你的痛覺神經明明是正常的，但在這種狀態下你還是這麼聒噪呢。"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"팔다리 좀 부러진 걸 가지고 뭘. 엄살 피우면서 간호 받을 생각에 벌써부터 행복한데?","JPN":"手足がちょっと折れただけで騒ぐも何もないもん。\\nあとで痛い痛いって訴えまくって介護してもらえると思ったらもう幸せ！","ENG":"Oh, it's just a few broken bones, that's all. The thought of getting all pampered in a hospital bed's getting me all giddy!","TWN":"是四肢骨折又不是嘴巴骨折，而且我只要哎個兩聲，就可以得到照顧，光想就覺得很幸福呢～"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"야호, 즐거운 농땡이 시간!","JPN":"やったあ、楽しいおサボりタイム！","ENG":"Woohoo! Now I can goof off legally!","TWN":"呀呵～可以光明正大摸魚囉～"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"아흐앗파여!?","JPN":"いたたたっ！","ENG":"OUCH?!!","TWN":"唉唷好痛！"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"펄떡거리지 마십시오. 치료 기간만 연장됩니다.","JPN":"ジタバタしないでください。治療期間が延びるだけです。","ENG":"Stop flailing about. You'll only extend the time it takes to heal.","TWN":"勸你動作還是不要太大，這樣只會增加休養時間。"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"아, 기다려. 호라이즌.","JPN":"ねえ、待ってよ、ホライズン！","ENG":"Wait, Horizon.","TWN":"喂，地平線，你等一下！"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"구급차 불러달라는 요청이라면 거절하겠습니다.","JPN":"救急車を呼んでほしいという要請ならお断りします。","ENG":"If you're about to ask me to call you an ambulance, I must decline.","TWN":"要我幫你叫救護車嗎？我拒絕。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"에이, 내가 그런 부탁을 할 리가 없잖아.","JPN":"ええーアタシがそんなことを頼むわけないでしょ。","ENG":"Aw, come on. You know I'd never ask such a thing.","TWN":"哎唷～我怎麼可能拜託你那種事～"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그렇다면 왜 불러세웠습니까.","JPN":"それではなぜ呼び止めたのですか。","ENG":"Then why did you beckon me to wait?","TWN":"那你為何叫住我？"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"그 윌버란 아저씨 말이야, 네가 올 때를 대비해 거창한 환영식을 준비해 뒀어.","JPN":"そのウィルバーっておじさんね、アンタが来ると想定して、だいぶ派手な歓迎会を準備してるよ。","ENG":"That Wilbur guy… He's prepared one heck of a surprise party to welcome you.","TWN":"那個叫韋爾伯的叔叔，他準備了一個盛大的派對要歡迎你。"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"내가 알려 줄 비상 통로를 따라가면 바로 뒤통수를 후려칠 수 있을 텐데, 어떡할래?","JPN":"アタシが知っている非常通路を使えば不意打ちを狙えると思うけど、どうする？","ENG":"I know an emergency exit route you could take to whack him from behind. How about it?","TWN":"我知道一個秘密通道，可以讓你殺他個措手不及，怎麼樣？你想知道嗎？"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"정면으로 갑니다.","JPN":"正面から行きます。","ENG":"I will face him from the front.","TWN":"我要正面迎戰。"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"프레임을 너무 믿는 거 아니니? 출력이 예전 같지 않던데?","JPN":"フレームを過信しすぎじゃない？　出力が前に比べてだいぶ弱くなってたよ？","ENG":"Aren't you relying on that frame of yours a tad much? Your power output's not what it used to be.","TWN":"你會不會太高估那副軀殼？我看你的輸出好像不如以往？"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"저는 수금 중 채무자를 위협하기 위해 이런 복장을 입었습니다. 수금이 수월하기 때문이죠.","JPN":"私は集金中に債務者を脅すため、このような服装をしています。集金が容易になるからです。","ENG":"I've dressed myself in this fashion to intimidate my debtors during collection. It can help facilitate the collection, you see.","TWN":"我穿這身服裝是為了要恫嚇某些債務人，方便討債。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};